FILES = {'backend/app/core/http_security.py': 'from __future__ import annotations\n\nfrom collections.abc import Awaitable, Callable\n\nfrom starlette.requests import Request\nfrom starlette.responses import Response\n\n\nSECURITY_HEADERS: dict[str, str] = {\n    "X-Content-Type-Options": "nosniff",\n    "X-Frame-Options": "DENY",\n    "Referrer-Policy": "no-referrer",\n    "Cross-Origin-Opener-Policy": "same-origin",\n}\n\n\nasync def add_security_headers(\n    request: Request,\n    call_next: Callable[[Request], Awaitable[Response]],\n) -> Response:\n    """Add safe default HTTP security headers."""\n\n    response = await call_next(request)\n\n    for header_name, header_value in SECURITY_HEADERS.items():\n        response.headers.setdefault(header_name, header_value)\n\n    if request.url.path.startswith("/api/"):\n        response.headers.setdefault("Cache-Control", "no-store")\n\n    return response\n', 'backend/app/main.py': 'from fastapi import FastAPI\nfrom fastapi.middleware.cors import CORSMiddleware\n\nfrom app.api.router import api_router\nfrom app.core.config import settings\nfrom app.core.http_security import add_security_headers\nfrom app.core.security_config import is_production_environment\n\n\ndef create_app() -> FastAPI:\n    """Create and configure the FastAPI application."""\n\n    is_production = is_production_environment(settings.environment)\n\n    app = FastAPI(\n        title=settings.app_name,\n        debug=settings.debug,\n        version="0.1.0",\n        description="Missio - Mission is possible.",\n        docs_url=None if is_production else "/docs",\n        redoc_url=None if is_production else "/redoc",\n        openapi_url=None if is_production else "/openapi.json",\n    )\n\n    app.middleware("http")(add_security_headers)\n\n    app.add_middleware(\n        CORSMiddleware,\n        allow_origins=[\n            "http://localhost:5173",\n            "http://127.0.0.1:5173",\n        ],\n        allow_credentials=True,\n        allow_methods=["*"],\n        allow_headers=["*"],\n    )\n\n    app.include_router(api_router)\n\n    @app.get("/")\n    def root() -> dict[str, str]:\n        return {\n            "message": "Missio backend is running.",\n            "slogan": "Mission is possible.",\n        }\n\n    return app\n\n\napp = create_app()\n', 'backend/app/api/routes/db_health.py': 'from fastapi import APIRouter, Depends\n\nfrom app.api.dependencies import require_roles_dependency\nfrom app.db.session import check_database_connection, get_sqlite_runtime_settings\nfrom app.models.user import User\n\nrouter = APIRouter(prefix="/db", tags=["database"])\n\n\n@router.get("/health")\ndef database_health_check(\n    current_user: User = Depends(require_roles_dependency("super_admin")),\n) -> dict[str, object]:\n    """Return database connection and SQLite runtime health details."""\n\n    del current_user\n\n    return {\n        "connection": check_database_connection(),\n        "runtime": get_sqlite_runtime_settings(),\n    }\n', 'backend/app/commands/check_api_security.py': 'from __future__ import annotations\n\nfrom sqlalchemy import delete\nfrom fastapi.testclient import TestClient\n\nimport app.models  # noqa: F401\nfrom app.db.session import SessionLocal\nfrom app.main import app\nfrom app.models.audit_log import AuditLog\nfrom app.models.login_attempt import LoginAttempt\nfrom app.models.user import User\nfrom app.repositories.user_repository import get_user_by_username, normalize_username\nfrom app.services.auth_service import create_user_with_password\n\n\nSUPER_ADMIN_USERNAME = "missio_api_security_admin"\nSTAFF_USERNAME = "missio_api_security_staff"\nTEST_PASSWORD = "Missio.2026!"\n\n\ndef cleanup_test_data() -> None:\n    """Delete records created by this command."""\n\n    db = SessionLocal()\n\n    try:\n        for username in [SUPER_ADMIN_USERNAME, STAFF_USERNAME]:\n            normalized_username = normalize_username(username)\n            user = get_user_by_username(\n                db=db,\n                username=normalized_username,\n                business_id=None,\n            )\n\n            if user is not None:\n                db.delete(user)\n\n            db.execute(\n                delete(LoginAttempt).where(\n                    LoginAttempt.username == normalized_username,\n                ),\n            )\n            db.execute(\n                delete(AuditLog).where(\n                    AuditLog.detail.like(f"%{normalized_username}%"),\n                ),\n            )\n\n        db.commit()\n    finally:\n        db.close()\n\n\ndef create_test_users() -> None:\n    """Create local users for API security checks."""\n\n    db = SessionLocal()\n\n    try:\n        create_user_with_password(\n            db=db,\n            full_name="Missio API Security Admin",\n            username=SUPER_ADMIN_USERNAME,\n            password=TEST_PASSWORD,\n            role="super_admin",\n            business_id=None,\n            email="missio.api.security.admin@example.com",\n            is_active=True,\n        )\n        create_user_with_password(\n            db=db,\n            full_name="Missio API Security Staff",\n            username=STAFF_USERNAME,\n            password=TEST_PASSWORD,\n            role="staff",\n            business_id=None,\n            email="missio.api.security.staff@example.com",\n            is_active=True,\n        )\n        db.commit()\n    finally:\n        db.close()\n\n\ndef login_and_get_token(client: TestClient, username: str) -> str:\n    """Login and return access token."""\n\n    response = client.post(\n        "/api/v1/auth/login",\n        json={\n            "username": username,\n            "password": TEST_PASSWORD,\n        },\n    )\n\n    if response.status_code != 200:\n        raise RuntimeError(f"Login failed for {username}: {response.text}")\n\n    return str(response.json()["access_token"])\n\n\ndef assert_security_headers(response) -> None:\n    """Validate required security headers."""\n\n    required_headers = {\n        "x-content-type-options": "nosniff",\n        "x-frame-options": "DENY",\n        "referrer-policy": "no-referrer",\n    }\n\n    for header_name, expected_value in required_headers.items():\n        actual_value = response.headers.get(header_name)\n\n        if actual_value != expected_value:\n            raise RuntimeError(\n                f"{header_name} header beklenen değerde değil: {actual_value}"\n            )\n\n\ndef main() -> None:\n    """Run API security smoke checks."""\n\n    cleanup_test_data()\n    create_test_users()\n\n    client = TestClient(app)\n\n    try:\n        root_response = client.get("/")\n\n        if root_response.status_code != 200:\n            raise RuntimeError("Root endpoint beklenen 200 cevabını vermedi.")\n\n        assert_security_headers(root_response)\n\n        unauth_me_response = client.get("/api/v1/auth/me")\n\n        if unauth_me_response.status_code != 401:\n            raise RuntimeError("/auth/me token olmadan 401 dönmeliydi.")\n\n        invalid_token_response = client.get(\n            "/api/v1/auth/me",\n            headers={"Authorization": "Bearer invalid-token"},\n        )\n\n        if invalid_token_response.status_code != 401:\n            raise RuntimeError("/auth/me geçersiz token ile 401 dönmeliydi.")\n\n        db_health_no_token = client.get("/api/v1/db/health")\n\n        if db_health_no_token.status_code != 401:\n            raise RuntimeError("/db/health token olmadan 401 dönmeliydi.")\n\n        staff_token = login_and_get_token(client, STAFF_USERNAME)\n        db_health_staff = client.get(\n            "/api/v1/db/health",\n            headers={"Authorization": f"Bearer {staff_token}"},\n        )\n\n        if db_health_staff.status_code != 403:\n            raise RuntimeError("/db/health staff için 403 dönmeliydi.")\n\n        admin_token = login_and_get_token(client, SUPER_ADMIN_USERNAME)\n        db_health_admin = client.get(\n            "/api/v1/db/health",\n            headers={"Authorization": f"Bearer {admin_token}"},\n        )\n\n        if db_health_admin.status_code != 200:\n            raise RuntimeError("/db/health super_admin için 200 dönmeliydi.")\n\n        assert_security_headers(db_health_admin)\n\n        if "password_hash" in db_health_admin.text:\n            raise RuntimeError("API response password_hash sızdırıyor.")\n\n        print("HTTP security header kontrolü başarılı.")\n        print("Unauthorized endpoint kontrolü başarılı.")\n        print("Invalid token kontrolü başarılı.")\n        print("Protected db health endpoint kontrolü başarılı.")\n        print("API güvenlik temel kontrolü başarılı.")\n    finally:\n        cleanup_test_data()\n\n\nif __name__ == "__main__":\n    main()\n', 'backend/tests/test_api_security.py': 'from collections.abc import Generator\n\nimport pytest\nfrom fastapi.testclient import TestClient\nfrom sqlalchemy import create_engine, event\nfrom sqlalchemy.orm import Session, sessionmaker\nfrom sqlalchemy.pool import StaticPool\n\nimport app.models  # noqa: F401\nfrom app.db.base import Base\nfrom app.db.session import get_db\nfrom app.main import app\nfrom app.services.auth_service import create_user_with_password\n\n\n@pytest.fixture()\ndef db_session() -> Generator[Session, None, None]:\n    engine = create_engine(\n        "sqlite://",\n        connect_args={"check_same_thread": False},\n        poolclass=StaticPool,\n    )\n\n    @event.listens_for(engine, "connect")\n    def enable_foreign_keys(dbapi_connection, connection_record) -> None:\n        del connection_record\n        cursor = dbapi_connection.cursor()\n        cursor.execute("PRAGMA foreign_keys=ON")\n        cursor.close()\n\n    TestingSessionLocal = sessionmaker(\n        autocommit=False,\n        autoflush=False,\n        bind=engine,\n    )\n\n    Base.metadata.create_all(bind=engine)\n\n    db = TestingSessionLocal()\n\n    try:\n        yield db\n    finally:\n        db.close()\n        Base.metadata.drop_all(bind=engine)\n        engine.dispose()\n\n\n@pytest.fixture()\ndef client(db_session: Session) -> Generator[TestClient, None, None]:\n    def override_get_db() -> Generator[Session, None, None]:\n        yield db_session\n\n    app.dependency_overrides[get_db] = override_get_db\n\n    try:\n        with TestClient(app) as test_client:\n            yield test_client\n    finally:\n        app.dependency_overrides.clear()\n\n\ndef create_user(\n    db: Session,\n    *,\n    username: str,\n    role: str,\n    password: str = "Missio.2026!",\n) -> None:\n    create_user_with_password(\n        db=db,\n        full_name=username.title(),\n        username=username,\n        password=password,\n        role=role,\n        business_id=None,\n        is_active=True,\n    )\n    db.commit()\n\n\ndef login(client: TestClient, username: str) -> str:\n    response = client.post(\n        "/api/v1/auth/login",\n        json={\n            "username": username,\n            "password": "Missio.2026!",\n        },\n    )\n\n    assert response.status_code == 200\n\n    return str(response.json()["access_token"])\n\n\ndef assert_security_headers(response) -> None:\n    assert response.headers["x-content-type-options"] == "nosniff"\n    assert response.headers["x-frame-options"] == "DENY"\n    assert response.headers["referrer-policy"] == "no-referrer"\n\n\ndef test_security_headers_are_added_to_root(client: TestClient) -> None:\n    response = client.get("/")\n\n    assert response.status_code == 200\n    assert_security_headers(response)\n\n\ndef test_me_endpoint_requires_token(client: TestClient) -> None:\n    response = client.get("/api/v1/auth/me")\n\n    assert response.status_code == 401\n\n\ndef test_me_endpoint_rejects_invalid_token(client: TestClient) -> None:\n    response = client.get(\n        "/api/v1/auth/me",\n        headers={"Authorization": "Bearer invalid-token"},\n    )\n\n    assert response.status_code == 401\n    assert response.json()["detail"] == "Oturum doğrulanamadı."\n\n\ndef test_db_health_requires_token(client: TestClient) -> None:\n    response = client.get("/api/v1/db/health")\n\n    assert response.status_code == 401\n\n\ndef test_db_health_rejects_staff_user(\n    client: TestClient,\n    db_session: Session,\n) -> None:\n    create_user(db_session, username="staffuser", role="staff")\n    token = login(client, "staffuser")\n\n    response = client.get(\n        "/api/v1/db/health",\n        headers={"Authorization": f"Bearer {token}"},\n    )\n\n    assert response.status_code == 403\n\n\ndef test_db_health_allows_super_admin(\n    client: TestClient,\n    db_session: Session,\n) -> None:\n    create_user(db_session, username="superadmin", role="super_admin")\n    token = login(client, "superadmin")\n\n    response = client.get(\n        "/api/v1/db/health",\n        headers={"Authorization": f"Bearer {token}"},\n    )\n\n    assert response.status_code == 200\n    assert_security_headers(response)\n    assert "password_hash" not in response.text\n\n\ndef test_api_responses_use_no_store_cache_header(\n    client: TestClient,\n    db_session: Session,\n) -> None:\n    create_user(db_session, username="superadmin", role="super_admin")\n    token = login(client, "superadmin")\n\n    response = client.get(\n        "/api/v1/auth/me",\n        headers={"Authorization": f"Bearer {token}"},\n    )\n\n    assert response.status_code == 200\n    assert response.headers["cache-control"] == "no-store"\n', 'docs/API_SECURITY.md': "# Missio API Security\n\nBu doküman Missio API yüzeyinin güvenlik sınıflandırmasını tutar.\n\n---\n\n## 1. Public Endpoint Listesi\n\nAşağıdaki endpointler token olmadan çalışabilir:\n\n| Method | Endpoint | Amaç |\n|---|---|---|\n| GET | `/` | Basit uygulama çalışma kontrolü |\n| GET | `/api/v1/health` | Basit servis sağlık kontrolü |\n| POST | `/api/v1/auth/login` | Kullanıcı girişi |\n\nPublic endpointler hassas veri döndürmemelidir.\n\n---\n\n## 2. Protected Endpoint Listesi\n\nAşağıdaki endpointler token ister:\n\n| Method | Endpoint | Yetki |\n|---|---|---|\n| GET | `/api/v1/auth/me` | Giriş yapmış kullanıcı |\n| GET | `/api/v1/db/health` | Sadece `super_admin` |\n\n---\n\n## 3. API Güvenlik Kuralları\n\n- Public olmayan endpointler token istemelidir.\n- Protected endpointlerde rol kontrolü yapılmalıdır.\n- Business scope gerektiren endpointlerde `business_id` kontrolü yapılmalıdır.\n- `password_hash`, secret veya gereksiz hassas veri response içinde dönmemelidir.\n- Hata cevaplarında stack trace veya teknik detay dönmemelidir.\n- API response'larında güvenlik headerları bulunmalıdır.\n- API response'ları için `Cache-Control: no-store` kullanılmalıdır.\n- Production ortamda `/docs`, `/redoc` ve `/openapi.json` kapatılmalıdır.\n\n---\n\n## 4. Mevcut API Güvenlik Testleri\n\nTest dosyası:\n\n```text\nbackend/tests/test_api_security.py\n```\n\nKontrol komutu:\n\n```powershell\npython -m app.commands.check_api_security\npython -m pytest tests/test_api_security.py\n```\n"}

CHECKLIST_REPLACEMENTS = {
    "- [ ] Public endpoint listesi açıkça belirlenecek.": "- [x] Public endpoint listesi açıkça belirlenecek.",
    "- [ ] Public olmayan endpointlerin tamamı token isteyecek.": "- [x] Public olmayan endpointlerin tamamı token isteyecek.",
    "- [ ] Hata cevapları güvenli.": "- [x] Hata cevapları güvenli.",
    "- [ ] Production ortamda debug kapalı olacak.": "- [x] Production ortamda debug kapalı olacak.",
}


def write_file(relative_path: str, content: str) -> None:
    target = ROOT_DIR / relative_path
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content, encoding="utf-8")
    print(f"Yazildi: {target}")


def update_security_checklist() -> None:
    if not SECURITY_CHECKLIST_PATH.exists():
        print("SECURITY_CHECKLIST.md bulunamadi, atlandi.")
        return

    content = SECURITY_CHECKLIST_PATH.read_text(encoding="utf-8")

    for old, new in CHECKLIST_REPLACEMENTS.items():
        content = content.replace(old, new)

    SECURITY_CHECKLIST_PATH.write_text(content, encoding="utf-8")
    print("SECURITY_CHECKLIST.md guncellendi.")


def compile_files() -> None:
    for relative_path in FILES:
        if relative_path.endswith(".py"):
            py_compile.compile(str(ROOT_DIR / relative_path), doraise=True)

    print("Python syntax kontrolu basarili.")


def main() -> None:
    print("Missio ADIM 5H API guvenlik sertlestirme ve testleri olusturuluyor.")
    print("")

    for relative_path, content in FILES.items():
        write_file(relative_path, content)

    update_security_checklist()
    compile_files()

    print("")
    print("Tamamlandi.")


if __name__ == "__main__":
    main()
